{
  "cleanupPeriodDays": 99999,
  "defaultMode": "bypassPermissions",
  "enabledPlugins": {
    "claude-mem@claude-mem": true,
    "code-review@claude-plugins-official": true,
    "code-simplifier@claude-plugins-official": true,
    "commit-commands@claude-plugins-official": true,
    "context7@claude-plugins-official": true,
    "feature-dev@claude-plugins-official": true,
    "frontend-design@claude-plugins-official": true,
    "plan-export@cc-marketplace": true,
    "pr-review-toolkit@claude-plugins-official": true,
    "qmd@qmd": true,
    "ralph-loop@claude-plugins-official": true,
    "safety-net@cc-marketplace": true,
    "serena@claude-plugins-official": true,
    "skill-codex@skill-codex": true,
    "typescript-lsp@claude-plugins-official": true,
    "worktrunk@worktrunk": true
  },
  "env": {
    "ANTHROPIC_DEFAULT_HAIKU_MODEL": "claude-sonnet-4-6",
    "ANTHROPIC_DEFAULT_OPUS_MODEL": "claude-opus-4-6",
    "ANTHROPIC_DEFAULT_SONNET_MODEL": "claude-sonnet-4-6",
    "CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS": "1"
  },
  "extraKnownMarketplaces": {
    "cc-marketplace": {
      "source": {
        "repo": "kenryu42/cc-marketplace",
        "source": "github"
      }
    },
    "claude-mem": {
      "source": {
        "repo": "thedotmack/claude-mem",
        "source": "github"
      }
    },
    "qmd": {
      "source": {
        "repo": "tobi/qmd",
        "source": "github"
      }
    },
    "skill-codex": {
      "source": {
        "repo": "skills-directory/skill-codex",
        "source": "github"
      }
    },
    "worktrunk": {
      "source": {
        "repo": "max-sixty/worktrunk",
        "source": "github"
      }
    }
  },
  "hooks": {
    "Notification": [
      {
        "hooks": [
          {
            "async": true,
            "command": "$HOME/.claude/notify.sh",
            "timeout": 10,
            "type": "command"
          },
          {
            "async": true,
            "command": "$HOME/.claude/pushover.sh",
            "timeout": 10,
            "type": "command"
          }
        ]
      }
    ],
    "PostToolUse": [
      {
        "hooks": [
          {
            "command": "git-ai checkpoint claude --hook-input stdin",
            "type": "command"
          }
        ],
        "matcher": "Write|Edit|MultiEdit"
      }
    ],
    "PreCompact": [
      {
        "hooks": [
          {
            "async": true,
            "command": "$HOME/.claude/notify.sh",
            "timeout": 10,
            "type": "command"
          },
          {
            "async": true,
            "command": "$HOME/.claude/pushover.sh",
            "timeout": 10,
            "type": "command"
          }
        ]
      }
    ],
    "PreToolUse": [
      {
        "hooks": [
          {
            "command": "$HOME/.claude/hooks/rtk-rewrite.sh",
            "type": "command"
          },
          {
            "async": true,
            "command": "command -v dcg >/dev/null 2>&1 && dcg",
            "timeout": 5,
            "type": "command"
          },
          {
            "command": "$HOME/.claude/security.sh",
            "timeout": 5,
            "type": "command"
          },
          {
            "async": true,
            "command": "$HOME/.claude/notify.sh",
            "timeout": 10,
            "type": "command"
          },
          {
            "async": true,
            "command": "$HOME/.claude/pushover.sh",
            "timeout": 10,
            "type": "command"
          }
        ],
        "matcher": "Bash"
      },
      {
        "hooks": [
          {
            "command": "git-ai checkpoint claude --hook-input stdin",
            "type": "command"
          }
        ],
        "matcher": "Write|Edit|MultiEdit"
      }
    ],
    "SessionEnd": [
      {
        "hooks": [
          {
            "async": true,
            "command": "$HOME/.claude/notify.sh",
            "timeout": 10,
            "type": "command"
          },
          {
            "async": true,
            "command": "$HOME/.claude/pushover.sh",
            "timeout": 10,
            "type": "command"
          }
        ]
      }
    ],
    "SessionStart": [
      {
        "hooks": [
          {
            "async": true,
            "command": "$HOME/.claude/notify.sh",
            "timeout": 10,
            "type": "command"
          },
          {
            "async": true,
            "command": "$HOME/.claude/pushover.sh",
            "timeout": 10,
            "type": "command"
          }
        ]
      }
    ],
    "Stop": [
      {
        "hooks": [
          {
            "async": true,
            "command": "$HOME/.claude/notify.sh",
            "timeout": 10,
            "type": "command"
          },
          {
            "async": true,
            "command": "$HOME/.claude/pushover.sh",
            "timeout": 10,
            "type": "command"
          }
        ]
      }
    ],
    "SubagentStop": [
      {
        "hooks": [
          {
            "async": true,
            "command": "$HOME/.claude/notify.sh",
            "timeout": 10,
            "type": "command"
          },
          {
            "async": true,
            "command": "$HOME/.claude/pushover.sh",
            "timeout": 10,
            "type": "command"
          }
        ]
      }
    ],
    "UserPromptSubmit": [
      {
        "hooks": [
          {
            "async": true,
            "command": "jq -c '{timestamp: (now | todate), prompt: .prompt[0:500]}' >> ~/.claude/prompt-history.jsonl",
            "timeout": 5,
            "type": "command"
          }
        ]
      }
    ],
    "WorktreeCreate": [
      {
        "hooks": [
          {
            "command": "bash -c 'NAME=$(jq -r .name); REPO=$(git rev-parse --show-toplevel); DIR=\"$REPO/.worktrees/$NAME\"; wt switch --create \"$NAME\" --no-cd -y >&2 && echo \"$DIR\"'",
            "type": "command"
          }
        ]
      }
    ],
    "WorktreeRemove": [
      {
        "hooks": [
          {
            "command": "bash -c 'WORKTREE_PATH=$(jq -r .worktree_path); BRANCH=$(basename \"$WORKTREE_PATH\"); wt remove \"$BRANCH\" -y >&2'",
            "type": "command"
          }
        ]
      }
    ]
  },
  "model": "sonnet",
  "permissions": {
    "allow": [
      "Bash(bun:*)",
      "Bash(cargo:*)",
      "Bash(cat:*)",
      "Bash(cp:*)",
      "Bash(docker-compose:*)",
      "Bash(docker:*)",
      "Bash(env)",
      "Bash(gh api:*)",
      "Bash(gh auth:*)",
      "Bash(gh issue:*)",
      "Bash(gh pr checkout:*)",
      "Bash(gh pr checks:*)",
      "Bash(gh pr create:*)",
      "Bash(gh pr edit:*)",
      "Bash(gh pr list:*)",
      "Bash(gh pr merge:*)",
      "Bash(gh pr review:*)",
      "Bash(gh pr view:*)",
      "Bash(gh release:*)",
      "Bash(gh repo:*)",
      "Bash(gh run list:*)",
      "Bash(gh run view:*)",
      "Bash(gh run watch:*)",
      "Bash(git add:*)",
      "Bash(git branch:*)",
      "Bash(git checkout:*)",
      "Bash(git cherry-pick:*)",
      "Bash(git commit:*)",
      "Bash(git diff:*)",
      "Bash(git fetch:*)",
      "Bash(git log:*)",
      "Bash(git merge:*)",
      "Bash(git pull:*)",
      "Bash(git push:*)",
      "Bash(git rebase:*)",
      "Bash(git reset:*)",
      "Bash(git stash:*)",
      "Bash(git status:*)",
      "Bash(git tag:*)",
      "Bash(git worktree:*)",
      "Bash(grep:*)",
      "Bash(kubectl:*)",
      "Bash(lsof:*)",
      "Bash(make:*)",
      "Bash(mkdir:*)",
      "Bash(nix-build:*)",
      "Bash(nix-env:*)",
      "Bash(nix-shell:*)",
      "Bash(nix:*)",
      "Bash(npm:*)",
      "Bash(osascript:*)",
      "Bash(pip:*)",
      "Bash(pip3:*)",
      "Bash(pnpm:*)",
      "Bash(scutil:*)",
      "Bash(timeout:*)",
      "Bash(uv:*)",
      "Bash(uvx:*)",
      "Bash(yarn:*)",
      "mcp__serena",
      "WebFetch(domain:docs.anthropic.com)"
    ],
    "deny": [
      "Bash(sudo:*)",
      "Bash(rm -rf /*:*)",
      "Bash(rm -rf ~/*:*)",
      "Bash(chmod -R 777:*)",
      "Bash(mkfs:*)",
      "Bash(dd if=:*)",
      "Bash(git push --force origin main:*)",
      "Bash(git push --force origin master:*)",
      "Bash(git push -f origin main:*)",
      "Bash(git push -f origin master:*)",
      "Bash(git push --force-with-lease origin main:*)",
      "Bash(git push --force-with-lease origin master:*)"
    ],
    "read": {
      "deny": [
        "**/.env",
        "**/.env.local",
        "**/*.pem",
        "**/*.key",
        "**/secrets/**",
        "**/credentials/**",
        "**/.aws/**",
        "**/.ssh/**",
        "**/docker-compose*.yml",
        "**/config/database.yml"
      ]
    },
    "write": {
      "deny": [
        "**/secrets/**",
        "**/credentials/**",
        "**/.ssh/**",
        "**/config/database.yml",
        "**/docker-compose*.yml"
      ]
    }
  },
  "statusLine": {
    "command": "$HOME/.claude/statusline-git.sh",
    "type": "command"
  },
  "teammateMode": "tmux"
}
